"use client";

import { Search, MapPin, Filter, Clock } from "lucide-react";
import { useSearchParams, useRouter } from "next/navigation";
import { useDebouncedSearchParams } from "@/hooks/useDebouncedSearchParams";

export default function SearchFilters() {
  const searchParams = useSearchParams();
  const router = useRouter();

  // 🔥 Debounced search (explicit key)
  const { value: search, setValue: setSearch } =
    useDebouncedSearchParams({
      key: "search",
      delay: 500,
    });

  const updateInstant = (key: string, value: string) => {
    const params = new URLSearchParams(searchParams.toString());

    if (!value || value === "All") {
      params.delete(key);
    } else {
      params.set(key, value);
    }

    router.push(`?${params.toString()}`);
  };

  return (
    <>
      {/* Search (debounced) */}
      <div className="relative flex-1 max-w-md">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-400" />
        <input
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder="Search lawyer..."
          className="w-full pl-10 pr-4 py-2 border rounded-lg"
        />
      </div>

      {/* Category (instant) */}
      <select
        value={searchParams.get("category") ?? "All"}
        onChange={(e) => updateInstant("category", e.target.value)}
      >
        <option>All</option>
        <option>Criminal Law</option>
        <option>Corporate Law</option>
      </select>

      {/* Location (instant) */}
      <select
        value={searchParams.get("location") ?? "All"}
        onChange={(e) => updateInstant("location", e.target.value)}
      >
        <option>All</option>
        <option>Hyderabad</option>
        <option>Delhi</option>
      </select>

      {/* Experience (instant) */}
      <select
        value={searchParams.get("minExp") ?? ""}
        onChange={(e) => updateInstant("minExp", e.target.value)}
      >
        <option value="">Any Exp</option>
        <option value="5">5+ yrs</option>
      </select>
    </>
  );
}
